        false,
        home,
      );

      assert.equal(succeeded, 1);
      assert.equal(failed.length, 0);
      assert.deepEqual(JSON.parse(await readFile(configFile, "utf-8")), {
        a: 1,
        b: 99,
      });
      assert.ok(!(await exists(backupPath)));
    } finally {
      await rm(home, { recursive: true, force: true });
    }
  });
});

