      assert.equal(entry.agent, "claude-code");
      if (entry.kind === "skill-dir") {
        assert.equal(entry.source, "/old/source");
        assert.equal(entry.method, "symlink");
      }
    } finally {
      await rm(home, { recursive: true });
    }
  });
});

