      const action: FileWriteRevertAction = {
        kind: "file-write",
        skill: "test-skill",
        agent: "claude-code",
        target: targetFile,
      };

      const { succeeded, skipped } = await executeRevert(
        [action],
        false,
        false,
        home,
      );
