  FileWriteRevertAction,
  FrontmatterEmitRevertAction,
  Manifest,
} from "../../src/types.ts";
import { exists, makeTmpDir } from "../helpers/fs.ts";

logger.silence();

const testManifest: Manifest = {
  skills: [
