+        skill: action.skill,
+        agent: action.agent,
+        target: action.target,
+      },
+      dryRun,
+      verbose,
+      home,
+      planned,
+      deps,
+    );
+  }
+
+  if (dryRun) {
+    planned.push({
+      verb: "unapply-patch",
+      kind: "frontmatter-emit",
+      skill: action.skill,
+      agent: action.agent,
+      target: action.target,
+      patch: frontmatterEntry.undoPatch,
+    });
+    return { outcome: "ok" };
+  }
