+          ? `removed: ${action.target}`
+          : `unapplied frontmatter patch from: ${action.target}`,
+      );
+    }
+    return { outcome: "ok" };
+  } catch (err) {
+    const msg = err instanceof Error ? err.message : String(err);
+    logger.fail(label, msg);
+    return { outcome: "fail", error: msg };
+  }
