      assert.ok(failed[0]?.error.includes("not managed by inception-engine"));
      assert.equal(await readFile(targetFile, "utf-8"), "original content");
    } finally {
      await rm(sourceDir, { recursive: true });
      await rm(home, { recursive: true, force: true });
