    try {
      const configFile = path.join(home, "config.json");
      await writeFile(configFile, JSON.stringify({ a: 1 }));

      const action: ConfigPatchDeployAction = {
        kind: "config-patch",
        skill: "test-skill",
        agent: "claude-code",
        target: configFile,
