        configFile,
        JSON.stringify({
          mcpServers: { "existing-server": { command: "old" } },
        }),
      );

      const action: ConfigPatchDeployAction = {
        kind: "config-patch",
        skill: "new-server",
        agent: "claude-code",
        target: configFile,
        patch: { mcpServers: { "new-server": { command: "new" } } },
      };

      const { succeeded, failed } = await executeDeploy(
        [action],
        false,
        false,
        home,
